const { exec } = require('child_process');
const { AzureFunction, Context, HttpRequest } = require('@azure/functions');
const path = require('path');
const fs = require('fs');

const allowedFormats = ['pdf', 'docx', 'txt']; // Explicit allowlist of formats

const httpTrigger = async function (context, req) {
    try {
        const inputFile = req.body.inputFile;
        const outputFormat = req.body.outputFormat;

        // Validate input
        if (!inputFile || !outputFormat) {
            context.res = {
                status: 400,
                body: 'Input file and output format are required.'
            };
            return;
        }

        if (!allowedFormats.includes(outputFormat)) {
            context.res = {
                status: 400,
                body: 'Invalid output format.'
            };
            return;
        }

        const inputFilePath = path.resolve('/tmp', path.basename(inputFile));
        const outputFilePath = path.resolve('/tmp', `${path.basename(inputFile, path.extname(inputFile))}.${outputFormat}`);

        // Ensure the input file exists
        if (!fs.existsSync(inputFilePath)) {
            context.res = {
                status: 404,
                body: 'Input file not found.'
            };
            return;
        }

        // Run LibreOffice in headless mode
        exec(`libreoffice --headless --convert-to ${outputFormat} ${inputFilePath} --outdir /tmp`, (error, stdout, stderr) => {
            if (error) {
                context.res = {
                    status: 500,
                    body: `Error converting document: ${stderr}`
                };
                return;
            }

            // Ensure the output file was created
            if (!fs.existsSync(outputFilePath)) {
                context.res = {
                    status: 500,
                    body: 'Conversion failed, output file not created.'
                };
                return;
            }

            // Read the converted file
            const fileBuffer = fs.readFileSync(outputFilePath);

            // Respond with the converted file
            context.res = {
                status: 200,
                body: fileBuffer,
                headers: {
                    'Content-Type': 'application/octet-stream',
                    'Content-Disposition': `attachment; filename=${path.basename(outputFilePath)}`
                }
            };

            // Clean up files
            fs.unlinkSync(inputFilePath);
            fs.unlinkSync(outputFilePath);
        });
    } catch (err) {
        context.res = {
            status: 500,
            body: 'Internal server error.'
        };
    }
};

module.exports = httpTrigger;